+    // Phase 2: add observations and move risk parameter toward boundary
+    for i in 0..8 {
+        scanner.observe(ParameterObservation {
+            parameter_id: "risk".into(),
+            value_millionths: 500_000 - i * 40_000,
+            tick: i as u64,
