+fn high_risk_payoffs(n: usize) -> Vec<i64> {
+    let mut payoffs: Vec<i64> = (0..n).map(|_| 50_000).collect();
+    let tail_start = n * 95 / 100;
+    for p in payoffs.iter_mut().skip(tail_start) {
